def load_valknut_base():
    if not PIL_OK:
        return None
    try:
        raw = base64.b64decode(VALKNUT_B64)
        buf = io.BytesIO(raw); buf.seek(0)
        return Image.open(buf).convert("RGBA")
    except Exception as e:
        print("Valknut decode error:", e)
        return None

def fmt_uptime(s):
    try:
        td = timedelta(seconds=int(s))
        h, r = divmod(td.seconds, 3600)
        m, sc = divmod(r, 60)
        return str(td.days)+"d "+str(h).zfill(2)+"h "+str(m).zfill(2)+"m "+str(sc).zfill(2)+"s"
    except Exception: return str(s)

def fmt_diff(d):
    try:
        d=float(d)
        if d>=1e12: return str(round(d/1e12,2))+" T"
        if d>=1e9:  return str(round(d/1e9, 2))+" G"
        if d>=1e6:  return str(round(d/1e6, 2))+" M"
        if d>=1e3:  return str(round(d/1e3, 2))+" K"
        return str(int(d))
    except Exception: return str(d)

def draw_vegvisir(canvas, cx, cy, r, color):
    canvas.delete("vegvisir")
    canvas.create_oval(cx-r,cy-r,cx+r,cy+r,outline=color,width=2,tags="vegvisir")
    ir=r*0.25
    canvas.create_oval(cx-ir,cy-ir,cx+ir,cy+ir,outline=color,width=2,tags="vegvisir")
    for i in range(8):
        angle=math.radians(i*45)
        x1=cx+ir*math.cos(angle); y1=cy-ir*math.sin(angle)
        x2=cx+r*math.cos(angle);  y2=cy-r*math.sin(angle)
        canvas.create_line(x1,y1,x2,y2,fill=color,width=2,tags="vegvisir")
        mx=cx+(r*0.75)*math.cos(angle); my=cy-(r*0.75)*math.sin(angle)
        perp=math.radians(i*45+90); tl=r*0.08
        canvas.create_line(mx+tl*math.cos(perp),my-tl*math.sin(perp),
                           mx-tl*math.cos(perp),my+tl*math.sin(perp),fill=color,width=2,tags="vegvisir")
        mx2=cx+(r*0.88)*math.cos(angle); my2=cy-(r*0.88)*math.sin(angle); tl2=r*0.05
        canvas.create_line(mx2+tl2*math.cos(perp),my2-tl2*math.sin(perp),
                           mx2-tl2*math.cos(perp),my2+tl2*math.sin(perp),fill=color,width=1,tags="vegvisir")

