class IPSetupDialog(tk.Toplevel):
    """First-run dialog: shown when no ravenminer_config.json exists."""
    def __init__(self, parent, current_ip=DEFAULT_MINER_IP):
        super().__init__(parent)
        self.result = current_ip
        self.title("RavenMiner HQ — Miner Setup")
        self.configure(bg=BG)
        self.resizable(True, True)
        self.grab_set()

        tk.Label(self, text="ᚱᚨᚡᛖᚱᚵᛖᚱᛖᚱ ᚺᛟᛃ",
                 font=("Courier", 18, "bold"), fg=GOLD_BRIGHT, bg=BG).pack(pady=(20, 4))
        tk.Label(self, text="Enter Miner IP Address",
                 font=("Courier", 13), fg=GOLD, bg=BG).pack()
        tk.Label(self, text="Saved to ravenminer_config.json next to the .exe",
                 font=("Courier", 9), fg=GOLD, bg=BG).pack(pady=(2, 12))

        self._ip_var = tk.StringVar(value=current_ip)
        ip_entry = tk.Entry(self, textvariable=self._ip_var,
                            font=("Courier", 16, "bold"), bg=COL_C, fg=GOLD_BRIGHT,
                            insertbackground=GOLD_BRIGHT, relief="flat",
                            highlightthickness=2, highlightbackground=PURPLE_DIM,
                            highlightcolor=PURPLE_GLOW, justify="center")
        ip_entry.pack(padx=40, pady=4, ipadx=10, ipady=8, fill="x")
        ip_entry.select_range(0, tk.END)
        ip_entry.focus_set()
        ip_entry.bind("<Return>", lambda e: self._confirm())

        tk.Button(self, text="✔  CONNECT",
                  font=("Courier", 12, "bold"), fg=BG, bg=GREEN,
                  activebackground="#66ff88", relief="flat", cursor="hand2",
                  command=self._confirm).pack(fill="x", padx=40, ipady=10, pady=16)

        self.protocol("WM_DELETE_WINDOW", self._confirm)
        self.update_idletasks()
        w = self.winfo_reqwidth(); h = self.winfo_reqheight()
        sw = self.winfo_screenwidth(); sh = self.winfo_screenheight()
        self.geometry(f"{w}x{h}+{(sw-w)//2}+{(sh-h)//2}")

    def _confirm(self):
        ip = self._ip_var.get().strip()
        if ip:
            self.result = ip
        self.destroy()

