        gear_cv.pack(pady=6)
        def _draw_gear(cv, hover=False):
            cv.delete("all")
            cx, cy, r_out, r_in, r_hub = 35, 35, 26, 18, 8
            fill_col    = GOLD_BRIGHT if hover else "#9d5fff"
            outline_col = "#ffffff"   if hover else "#c9a84c"
            hub_fill    = "#ffffff"   if hover else "#7b2fff"
            hub_out     = GOLD_BRIGHT if hover else "#9d5fff"
            teeth = 10
            pts = []
            for i in range(teeth * 2):
                angle = math.radians(i * (360 / (teeth * 2)))
                r = r_out if i % 2 == 0 else r_in
                pts += [cx + r * math.cos(angle), cy + r * math.sin(angle)]
            if hover:
                # glow halo - solid colour, no alpha
                cv.create_oval(cx-r_out-6, cy-r_out-6, cx+r_out+6, cy+r_out+6,
                               fill="", outline=GOLD, width=4)
            cv.create_polygon(pts, fill=fill_col, outline=outline_col, width=1)
            cv.create_oval(cx-r_hub, cy-r_hub, cx+r_hub, cy+r_hub,
                           fill=hub_fill, outline=hub_out, width=2)

        def _gear_enter(e):
            _draw_gear(gear_cv, hover=True)
            rune_lbl.config(fg=GOLD_BRIGHT, font=("Segoe UI", 18, "bold"))

        def _gear_leave(e):
            _draw_gear(gear_cv, hover=False)
            rune_lbl.config(fg=PURPLE_DIM, font=("Segoe UI", 18))

        _draw_gear(gear_cv, hover=False)
        gear_cv.bind("<Enter>",    _gear_enter)
        gear_cv.bind("<Leave>",    _gear_leave)
