    def _stat_block(self,p,label,value,unit,fg,attr,bg,small=False):
        f=tk.Frame(p,bg=bg); f.pack(fill="x",padx=16,pady=3)
        tk.Label(f,text=label,font=("Courier",11),fg=GOLD,bg=bg).pack(anchor="w")
